    `,data:{features:Ft}},_t=[{icon:"savings",color:"#B5EAD7",title:"Zero API cost",desc:"Giselo talks to Claude CLI, OpenCode, and Codex directly — not through their paid APIs. No per-token billing, no monthly quotas. You already have the CLI authenticated; Giselo just uses it."},{icon:"hearing",color:"#A3D8F4",title:"Local speech — or cloud when you want",desc:"Transcription runs on faster-whisper (CPU, fully offline). Voice synthesis defaults to piper-tts locally — your audio never leaves your machine. If you prefer studio quality, flip a switch to use ElevenLabs with your own cloned voice."},{icon:"lock",color:"#D0BCFF",title:"True privacy by default",desc:"Nothing is sent to a third-party speech service unless you opt in. Your conversations stay in a local JSON file. No telemetry, no analytics, no account required."},{icon:"bolt",color:"#FFD700",title:"No intermediary latency",desc:"Responses stream directly from the CLI process to your speakers. There is no SaaS layer, no webhook, no message queue between you and the model."},{icon:"desktop_windows",color:"#FF9AA2",title:"Built for the desktop",desc:"A floating overlay that appears on hotkey and disappears when done. It does not hijack a browser tab or require a chat app open. Works while you code, design, or write."},{icon:"wifi_off",color:"#FFDAC1",title:"Works offline (mostly)",desc:"Whisper transcribes without internet. piper-tts speaks without internet. Only the LLM call requires a connection — and even that can be swapped for a local model."}],It=[{feature:"LLM cost",giselo:"Free (CLI)",others:"Per-token API billing"},{feature:"Speech-to-text",giselo:"Local (Whisper)",others:"Cloud API (charged)"},{feature:"Text-to-speech",giselo:"Local (piper-tts) or ElevenLabs (opt-in)",others:"Cloud API only (charged)"},{feature:"Audio privacy",giselo:"Local by default",others:"Sent to cloud"},{feature:"Streaming + Cancel",giselo:"✓ (sentence-level TTS)",others:"Rarely"},{feature:"Persona / gender",giselo:"✓ (hot-reload, no restart)",others:"✗"},{feature:"Toggleable skills",giselo:"✓ (custom .md files)",others:"✗"},{feature:"Desktop overlay",giselo:"✓",others:"✗"},{feature:"Wake word (offline)",giselo:"✓",others:"Rarely"}],Dt={template:`
